stylesheet:
QWidget { background: #17191f; color: #d7e6ff; }
QLabel { color: #8fd7ff; }
QGroupBox { border: 1px solid #435063; border-radius: 5px; margin-top: 8px; color: #f6c177; font-weight: 600; }
QGroupBox::title { subcontrol-origin: margin; left: 8px; padding: 0 4px; }
QLineEdit, QSpinBox, QListWidget, QTextEdit, QComboBox, QTreeWidget { background: #20242d; color: #e7f0ff; border: 1px solid #59677c; selection-background-color: #2f80ed; selection-color: #ffffff; }
QPushButton, QToolButton { background: #252b36; color: #9cdcfe; border: 1px solid #667891; padding: 6px 10px; font-weight: 600; }
QPushButton:hover, QToolButton:hover { background: #303849; color: #c3f4ff; border-color: #8fd7ff; }
QCheckBox { color: #c3e88d; }
QDockWidget::title { background: #20242d; color: #f6c177; padding: 6px; font-weight: 700; }
QTabBar::tab { background: #20242d; color: #9cdcfe; padding: 6px 10px; border: 1px solid #435063; }
QTabBar::tab:selected { background: #2b3342; color: #f6c177; font-weight: 700; }
QStatusBar { color: #c3e88d; }
QMdiSubWindow { background: #20242d; color: #d7e6ff; border: 1px solid #59677c; }
QMdiSubWindow:focus { color: #f6c177; border: 2px solid #8fd7ff; font-weight: 800; }
